arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty environment variables are now preserved
        // instead of being treated as unset (returned as null). This means
        // GetEnvironmentVariable returns "" for `export MY_FLAG=""` instead of null.
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null)
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
        else if (val.Length == 0)
        {
            Console.WriteLine("MY_FLAG explicitly set to empty");
        }
    }
}

